import pytest
from calc import safe_divide, percent


def test_safe_divide_normal():
    assert safe_divide(10, 2) == 5


def test_safe_divide_zero():
    with pytest.raises(ZeroDivisionError):
        safe_divide(10, 0)


def test_percent():
    assert percent(1, 3) == pytest.approx(33.333, rel=1e-3)

